INSERT INTO public.aircraft (id,created_at,updated_at,owner_id,name,notes,serial_number,aircraft_type) VALUES 
('abc8efe3-8e38-5adf-8612-381fed13b750', DEFAULT, DEFAULT, NULL, 'Hoc aliquid perspici sed discere.', 'Temnitati ea quem aut necest.', 'Sapienum malissius locus ille numquam.', 'Adest nostris omi repud dolorum quo multo, nat ut quod nosci has magnusquam etur.'), 
('b7f4c598-9783-5a9d-a1b1-b116c9358c5b', DEFAULT, DEFAULT, NULL, 'Potesse iud idem gravis cum cere tantum nos, neglexermit quae percipitis esset vel.', 'Mea et rectas me a, maiorum ut efficeruis qui probare aut voluptate.', 'Neque abo timusant primum res ac discipi.', 'Imo natura mihi in alis quaerit horreant, titiam efflueret et voluptatib quam.'), 
('8013f6e0-8bf3-5f87-95ec-dd13ff8c47a2', DEFAULT, DEFAULT, NULL, 'Admirare quadamordat time sic quam.', 'Efficille quod his endi conficiantur denique est, gregesse novumquam desis afferre dolor qui si.', 'Quantum defentium quos morbos proficet lendus, idem explicabil ratio aegritum hoc neque.', 'Est arum autem quisquam malo, et sed posse ab aut maior de esse.');
INSERT INTO public.flight_legs (id,created_at,updated_at,pilot_id,aircraft_id,location,altitude_m,temp_c,title,description) VALUES 
('19e27b39-411e-5bf3-9db0-e20f9ea44762', DEFAULT, DEFAULT, '8c8ac6ba-e229-5c1c-a2f4-598c83516e99', 'abc8efe3-8e38-5adf-8612-381fed13b750', 'Voluptatem aut clarisque est habetiam inter enimprobat, propter omos tur semelabo proptereant nec.', 15032, 95, 'Quae voluptate cum quam et physicis.', 'Quidem omne nec sine fallare contem quod quidem, honesse esse dicat sic cadere cum.'), 
('2c372530-368a-5e23-8a5a-d40469170490', DEFAULT, DEFAULT, '334d7e34-c1f4-5f40-83ab-b5068d6a4555', 'b7f4c598-9783-5a9d-a1b1-b116c9358c5b', 'Et explicarum sapiens sed dolorum quibus, philos nihil qui iniure quid si bonore.', 46251, 27, 'Aut quae homines et issimum tamendit qui.', 'Entium cognitudit tore paria a dixi.'), 
('693cdada-9a79-5151-84d4-7c6a638ecbb9', DEFAULT, DEFAULT, '60291f90-4d49-5434-9c5e-3a5aaf62c9fb', '8013f6e0-8bf3-5f87-95ec-dd13ff8c47a2', 'Ferat etsi et quidem id etiam.', 12223, 67, 'Modum scribens alii et tria praestabilius enimperman in, ini aeterat mis sine maiores maius quae vivamural.', 'In sapiente optio nos in, captet plato dividonem lud romanimo.');
